#[derive(Debug, Clone, Default, rustler::NifMap)]
pub struct PaddleOcrConfig {
    pub language: String,
    pub cache_dir: Option<String>,
    pub use_angle_cls: bool,
    pub enable_table_detection: bool,
    pub det_db_thresh: f32,
    pub det_db_box_thresh: f32,
    pub det_db_unclip_ratio: f32,
    pub det_limit_side_len: u32,
    pub rec_batch_num: u32,
    pub padding: u32,
    pub drop_score: f32,
    pub model_tier: String,
}

impl PaddleOcrConfig {
    pub fn new(opts: std::collections::HashMap<String, rustler::Term>) -> Self {
        Self {
            language: opts.get("language").and_then(|t| t.decode().ok()).unwrap_or_default(),
            cache_dir: opts.get("cache_dir").and_then(|t| t.decode().ok()),
            use_angle_cls: opts
                .get("use_angle_cls")
                .and_then(|t| t.decode().ok())
                .unwrap_or_default(),
            enable_table_detection: opts
                .get("enable_table_detection")
                .and_then(|t| t.decode().ok())
                .unwrap_or_default(),
            det_db_thresh: opts
                .get("det_db_thresh")
                .and_then(|t| t.decode().ok())
                .unwrap_or_default(),
            det_db_box_thresh: opts
                .get("det_db_box_thresh")
                .and_then(|t| t.decode().ok())
                .unwrap_or_default(),
            det_db_unclip_ratio: opts
                .get("det_db_unclip_ratio")
                .and_then(|t| t.decode().ok())
                .unwrap_or_default(),
            det_limit_side_len: opts
                .get("det_limit_side_len")
                .and_then(|t| t.decode().ok())
                .unwrap_or_default(),
            rec_batch_num: opts
                .get("rec_batch_num")
                .and_then(|t| t.decode().ok())
                .unwrap_or_default(),
            padding: opts.get("padding").and_then(|t| t.decode().ok()).unwrap_or_default(),
            drop_score: opts.get("drop_score").and_then(|t| t.decode().ok()).unwrap_or_default(),
            model_tier: opts.get("model_tier").and_then(|t| t.decode().ok()).unwrap_or_default(),
        }
    }
}

